import React, { useState, useContext, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { CartContext } from "../context/CartContext";

// ĐÃ SỬA ĐƯỜNG DẪN: Lùi 1 cấp ra khỏi pages, đi vào data/mockProducts
import { products } from "../data/mockProducts"; 

const ProductDetail = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const { addToCart } = useContext(CartContext);

  const [product, setProduct] = useState(null);
  const [mainImage, setMainImage] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        setLoading(true);
        const response = await fetch(`http://localhost:8080/api/products/${id}`);
        if (response.ok) {
          const data = await response.json();
          setProduct(data);
          if (data.images && data.images.length > 0) setMainImage(data.images[0]);
          else if (data.image) setMainImage(data.image);
        } else {
          // Tìm trong mảng dữ liệu import từ file data
          const localProduct = products.find(p => p.id === parseInt(id));
          if (localProduct) {
            setProduct(localProduct);
            setMainImage(localProduct.image);
          }
        }
      } catch (error) {
        console.error("Lỗi API:", error);
        // Fallback về file dữ liệu cục bộ khi lỗi mạng
        const localProduct = products.find(p => p.id === parseInt(id));
        if (localProduct) {
          setProduct(localProduct);
          setMainImage(localProduct.image);
        }
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
    window.scrollTo(0, 0);
  }, [id]);

  if (loading) return <div className="text-center py-20 font-medium text-gray-500">Đang tải sản phẩm...</div>;
  if (!product) return <div className="text-center py-20 font-medium text-red-500">Sản phẩm không tồn tại!</div>;

  // Tính giảm giá
  const discount = product.oldPrice && product.oldPrice > product.price
    ? Math.round(((product.oldPrice - product.price) / product.oldPrice) * 100)
    : 0;

  const increaseQty = () => setQuantity((prev) => prev + 1);
  const decreaseQty = () => quantity > 1 && setQuantity((prev) => prev - 1);

  const handleAddToCart = (redirect = false) => {
    addToCart({
      id: product.id,
      name: product.name,
      price: product.price,
      image: mainImage || product.image,
      qty: quantity,
    });

    if (redirect) {
      navigate("/checkout");
    }
  };

  // Lấy sản phẩm liên quan từ mảng dữ liệu chuẩn
  const relatedProducts = products.filter(p => p.id !== product.id).slice(0, 4);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Breadcrumb */}
      <div className="border-b border-gray-200 bg-white">
        <div className="max-w-7xl mx-auto px-6 py-5">
          <p className="text-sm text-gray-500">
            Trang chủ / TẤT CẢ SẢN PHẨM / <span className="text-green-600 font-medium">{product.name}</span>
          </p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-12">
        <div className="grid lg:grid-cols-2 gap-12">
          {/* Cột Trái: Ảnh Sản phẩm */}
          <div>
            <div className="flex gap-5">
              <div className="flex flex-col gap-4">
                {product.images && product.images.length > 0 ? (
                  product.images.map((img, index) => (
                    <button
                      key={index}
                      onClick={() => setMainImage(img)}
                      className={`w-24 h-24 rounded-2xl overflow-hidden border-2 transition-all duration-300 ${
                        mainImage === img ? "border-green-500 shadow-lg" : "border-gray-200"
                      }`}
                    >
                      <img src={img} alt="thumbnail" className="w-full h-full object-cover" />
                    </button>
                  ))
                ) : (
                  <button className="w-24 h-24 rounded-2xl overflow-hidden border-2 border-green-500 shadow-sm">
                    <img src={product.image || mainImage} alt="thumbnail" className="w-full h-full object-cover" />
                  </button>
                )}
              </div>

              <div className="flex-1 bg-white rounded-[36px] overflow-hidden border border-gray-100 shadow-xl max-h-[500px]">
                <img
                  src={mainImage || product.image || "https://picsum.photos/600/600"}
                  alt={product.name}
                  className="w-full h-full object-cover hover:scale-105 transition-transform duration-700"
                />
              </div>
            </div>
          </div>

          {/* Cột Phải: Thông tin chi tiết */}
          <div>
            <span className="inline-block px-4 py-2 rounded-full bg-green-100 text-green-700 text-sm font-semibold">
              {product.tag || 'HEALTHY SNACK'}
            </span>

            <h1 className="text-4xl font-bold text-gray-800 mt-5 leading-tight">
              {product.name}
            </h1>

            <div className="flex flex-wrap gap-8 mt-6 text-gray-500">
              <p>Thương hiệu: <span className="text-gray-700 font-medium">{product.brand || "Nông Lâm Store"}</span></p>
              <p>Mã sản phẩm: <span className="text-gray-700 font-medium">{product.sku || `NLF-${product.id}`}</span></p>
            </div>

            <div className="mt-8 p-6 rounded-[32px] bg-green-50 border border-green-100">
              <div className="flex flex-wrap items-center gap-4">
                <span className="text-5xl font-bold text-green-600">
                  {Number(product.price || 0).toLocaleString("vi-VN")}đ
                </span>
                {product.oldPrice && (
                  <>
                    <span className="text-2xl text-gray-400 line-through">
                      {Number(product.oldPrice).toLocaleString("vi-VN")}đ
                    </span>
                    {discount > 0 && (
                      <span className="px-4 py-2 rounded-full bg-red-100 text-red-600 font-semibold">
                        -{discount}%
                      </span>
                    )}
                  </>
                )}
              </div>
              {product.oldPrice && product.oldPrice > product.price && (
                <p className="text-gray-500 mt-4">
                  Tiết kiệm: <span className="font-semibold text-red-500">{(product.oldPrice - product.price).toLocaleString("vi-VN")}đ</span>
                </p>
              )}
            </div>

            <div className="mt-8">
              <h3 className="text-2xl font-bold text-gray-800">Mô tả sản phẩm</h3>
              <p className="text-gray-600 leading-relaxed mt-4 text-lg">
                {product.description || `Sản phẩm ${product.name} được chế biến theo quy trình công nghệ hiện đại, giữ trọn hương vị tự nhiên, thơm ngon và giàu dưỡng chất, cực kỳ tốt cho sức khỏe.`}
              </p>
            </div>

            {/* Khối chính sách ship */}
            <div className="mt-8 bg-white border border-gray-100 rounded-[28px] p-6 shadow-sm">
              <div className="space-y-4">
                <div className="flex gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-green-100 flex items-center justify-center font-bold text-green-700 shrink-0">01</div>
                  <div>
                    <p className="font-semibold text-gray-800">Đồng giá ship toàn quốc 30.000đ</p>
                    <p className="text-gray-500 mt-1">Giao hàng nhanh và an toàn</p>
                  </div>
                </div>
                <div className="flex gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-green-100 flex items-center justify-center font-bold text-green-700 shrink-0">02</div>
                  <div>
                    <p className="font-semibold text-gray-800">Miễn phí ship từ 300.000đ</p>
                    <p className="text-gray-500 mt-1">Áp dụng toàn quốc</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Khối Voucher */}
            <div className="mt-8">
              <h3 className="text-2xl font-bold text-gray-800 mb-5">Mã giảm giá</h3>
              <div className="flex flex-wrap gap-4">
                {["NLF100", "NLF300", "NLF500", "NLF1000"].map((code, index) => (
                  <div key={index} className="px-5 py-3 rounded-2xl bg-white border border-dashed border-green-300 text-green-700 font-semibold shadow-sm">
                    {code}
                  </div>
                ))}
              </div>
            </div>

            {/* Bộ tăng giảm số lượng & Đặt mua */}
            <div className="mt-10">
              <div className="flex items-center gap-5">
                <span className="font-semibold text-gray-700">Số lượng</span>
                <div className="flex items-center bg-white border border-gray-200 rounded-2xl overflow-hidden">
                  <button onClick={decreaseQty} className="w-14 h-14 text-xl font-semibold hover:bg-gray-100 transition">-</button>
                  <div className="w-16 text-center font-semibold text-lg">{quantity}</div>
                  <button onClick={increaseQty} className="w-14 h-14 text-xl font-semibold hover:bg-gray-100 transition">+</button>
                </div>
              </div>

              <div className="flex flex-col sm:flex-row gap-5 mt-8">
                <button
                  onClick={() => handleAddToCart(false)}
                  className="flex-1 py-5 rounded-3xl border-2 border-green-600 text-green-700 font-semibold text-lg hover:bg-green-50 transition-all duration-300"
                >
                  Thêm vào giỏ hàng
                </button>
                <button
                  onClick={() => handleAddToCart(true)}
                  className="flex-1 py-5 rounded-3xl bg-green-600 hover:bg-green-700 text-white font-semibold text-lg shadow-xl transition-all duration-300"
                >
                  Mua ngay
                </button>
              </div>

              <div className="mt-4">
                <button
                  onClick={() => navigate("/")}
                  className="w-full py-4 rounded-3xl bg-gray-200 hover:bg-gray-300 text-gray-700 font-semibold transition duration-300"
                >
                  QUAY VỀ TRANG CHỦ
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* PHẦN SẢN PHẨM LIÊN QUAN */}
        <div className="mt-24">
          <div className="text-center mb-12">
            <span className="inline-block px-5 py-2 rounded-full bg-green-100 text-green-700 text-sm font-semibold">
              RELATED PRODUCTS
            </span>
            <h2 className="text-4xl font-bold text-gray-800 mt-6">Sản phẩm thường mua cùng</h2>
          </div>

          <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-8">
            {relatedProducts.map((item) => (
              <div key={item.id} className="bg-white rounded-[32px] overflow-hidden border border-gray-100 shadow-sm hover:shadow-2xl transition-all duration-500 flex flex-col justify-between">
                <div className="h-72 overflow-hidden bg-gray-100">
                  <img
                    src={item.image}
                    alt={item.name}
                    className="w-full h-full object-cover hover:scale-110 transition-transform duration-700"
                  />
                </div>
                <div className="p-6 flex-1 flex flex-col justify-between">
                  <div>
                    <h3 className="text-xl font-semibold text-gray-800 line-clamp-1">{item.name}</h3>
                    <p className="text-green-600 font-bold text-2xl mt-4">{item.price.toLocaleString("vi-VN")}đ</p>
                  </div>
                  <button
                    onClick={() => navigate(`/product/${item.id}`)}
                    className="w-full mt-6 py-3.5 rounded-2xl bg-green-600 hover:bg-green-700 text-white font-semibold transition"
                  >
                    Xem sản phẩm
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

export default ProductDetail;
